import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [clicked, setClicked] = useState(false);
  const [isHovering, setIsHovering] = useState(false);

  return (
    <motion.section
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={() => setIsHovering(false)}
      onClick={() => {
        setClicked(true);
        setTimeout(() => setClicked(false), 3000);
      }}
      initial={{ scale: 1 }}
      animate={{
        scale: clicked ? 1.05 : 1,
        backgroundColor: isHovering ? "#154734" : "transparent",
        color: isHovering ? "#ddcba4" : "#000000",
      }}
      transition={{ duration: clicked ? 0.3 : 0.2 }}
      style={{
        cursor: "pointer",
        borderRadius: "1rem",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        color: isHovering ? "#ddcba4" : "#000000",
        ...style,
      }}
    >
      {/* Aplica el color también directamente a los hijos si es necesario */}
      <div style={{ width: "100%", color: isHovering ? "#ddcba4" : "#000000" }}>
        {children}
      </div>
    </motion.section>
  );
};

export default AnimatedSection;
